import React, { useEffect, useState } from "react";

function App() {
    const [data, setData] = useState([]);

    useEffect(() => {
        fetch("https://odaktedarik-my.sharepoint.com/personal/gorkem_cadirci_odaklojistik_com_tr/Documents/JSON/veri.json")
            .then((res) => res.json())
            .then((jsonData) => {
                setData(jsonData);
            })
            .catch((error) => console.error("JSON okuma hatası:", error));
    }, []);

    return (
        <div className="App">
            <h1>TEDARİK PERFORMANS RAPORU (JSON)</h1>
            <table border="1" style={{ borderCollapse: "collapse", width: "100%" }}>
                <thead>
                    <tr>
                        {data.length > 0 &&
                            Object.keys(data[0]).map((key) => (
                                <th key={key}>{key}</th>
                            ))}
                    </tr>
                </thead>
                <tbody>
                    {data.map((row, idx) => (
                        <tr key={idx}>
                            {Object.values(row).map((val, i) => (
                                <td key={i}>{val}</td>
                            ))}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}

export default App;
